effect.shader:
mat2 rot(float a) {
    float c = cos(a);
    float s = sin(a);
    return mat2(
        c, -s,
        s, c
    );
}

void main() {

    vec2 sizeVec = vec2(size,size);
    if( stretch > 0.0 ) {
        sizeVec.x *= 1.0 + (stretch/5.0);
    } else if( stretch < 0.0 ) {
        sizeVec.y *= 1.0 - (stretch/5.0);
    }

    vec2 pixelSize = sizeVec / acScreenSize;
    vec2 st = acScreenNorm;
    if( !screenSpace )
        st -= acLayerCenterNorm;
    st *= rot(angle * 0.0174533);
    st -= offset/1000.0;
    vec2 posInPixel = mod(st,pixelSize);
    posInPixel -= pixelSize/2.0;
    posInPixel *= rot(-angle * 0.0174533);
    posInPixel += pixelSize/2.0;
    vec2 pixelCenter = acScreenNorm - posInPixel + pixelSize / 2.0;

    float distCenter = smoothstep(0.0, 1.0, length((posInPixel/pixelSize) - vec2(0.5,0.5)));

    vec4 color = texture2DCv(inputImg.texture,pixelCenter);
    float tclamp = step(threshold, color.a);
    if( color.a > 0.0 && saturation > 0.0 ) {
        color /= color.a / max(color.a,saturation);
    }
    color = color * tclamp;
    //color = mix(color, vec4(0.0,0.0,0.0,color.a), vignette * distCenter);
    color = mix(color, vec4(min(color.rgb * color.rgb * color.rgb, vec3(0.9, 0.9, 0.9)),color.a * color.a * color.a), step(1.5, size) * vignette * distCenter);
    //color = vec4(color.rgb * (1.0-(vignette*distCenter)), color.a);
    gl_FragColor = color;
}
